#include <stdio.h>
#include <math.h>
#include <stdbool.h>

bool checkSquareSum(long long c) {
    long long left = 0;
    long long right = (long long)sqrt((double)c);
    while (left <= right) {
        long long sum = left * left + right * right;
        if (sum == c) return true;
        if (sum < c) ++left; else --right;
    }
    return false;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long c;
        scanf("%lld", &c);
        printf("%s\n", checkSquareSum(c) ? "true" : "false");
    }
    return 0;
}

