import sys, math

def check_square_sum(c: int) -> bool:
    left = 0
    right = math.isqrt(c)
    while left <= right:
        s = left * left + right * right
        if s == c:
            return True
        if s < c:
            left += 1
        else:
            right -= 1
    return False

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        c = int(data[idx]); idx += 1
        out.append('true' if check_square_sum(c) else 'false')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

